class Solution:
    def smallestPalindrome(self, s):
        from collections import Counter
        cnt = Counter(s)
        left = []
        mid = ''
        for ch in sorted(cnt):
            c = cnt[ch]
            left.append(ch * (c // 2))
            if c % 2 == 1:
                mid = ch
        half = ''.join(left)
        return half + mid + half[::-1]

