class Solution:
    def smallestPalindrome(self, s):
        cnt = [0] * 26
        for ch in s:
            cnt[ord(ch) - 97] += 1
        half_chars = []
        mid = ''
        for i in range(26):
            half_chars.append(chr(97 + i) * (cnt[i] // 2))
            if cnt[i] % 2 == 1:
                mid = chr(97 + i)
        h = ''.join(half_chars)
        return h + mid + h[::-1]

