var smallestPalindrome = function(s) {
    const cnt = new Array(26).fill(0);
    for (const ch of s) cnt[ch.charCodeAt(0) - 97]++;
    let h = '';
    let mid = '';
    for (let i = 0; i < 26; i++) {
        h += String.fromCharCode(97 + i).repeat(Math.floor(cnt[i] / 2));
        if (cnt[i] % 2 === 1) mid = String.fromCharCode(97 + i);
    }
    return h + mid + h.split('').reverse().join('');
};
